module priority_enc_8bit(
  input [7:0] request,
  output reg [2:0] priority,
  output reg valid
);

  always @(request[7:4])
  begin
    if (request[7])
      priority = 3'b111;
    else if (request[6])
      priority = 3'b110;
    else if (request[5])
      priority = 3'b101;
    else if (request[4])
      priority = 3'b100;
    else if (request[3])
      priority = 3'b011;
    else if (request[2])
      priority = 3'b010;
    else if (request[1])
      priority = 3'b001;
    else
      priority = 3'b000;
    valid = |request;
  end

endmodule

